/* jepson_map.js — Jepson Interactive Map assets and drawing engine
   Extracted from regions.html to enable browser caching.
   Loaded via <script src="jepson_map.js"> in regions.html */

const W=1060,H=1188;
const REGIONS=[{"idx": 3, "name": "North Coast", "code": "NCo", "color": "#3f736e", "order": 1}, {"idx": 16, "name": "North Coast Ranges", "code": "NCoR", "color": "#6d9d7a", "order": 2}, {"idx": 18, "name": "Klamath Ranges", "code": "KR", "color": "#8fa26e", "order": 3}, {"idx": 1, "name": "Cascade Ranges", "code": "CaR", "color": "#4f7a5a", "order": 4}, {"idx": 14, "name": "Sierra Nevada Foothills", "code": "SNF", "color": "#93a6bc", "order": 5}, {"idx": 13, "name": "High Sierra Nevada", "code": "SNH", "color": "#797db6", "order": 6}, {"idx": 5, "name": "Tehachapi Mountain", "code": "Teh", "color": "#7c93ae", "order": 7}, {"idx": 12, "name": "Great Central Valley", "code": "GV", "color": "#b7c26b", "order": 8}, {"idx": 15, "name": "San Francisco Bay Area", "code": "SnFrB", "color": "#aaced0", "order": 9}, {"idx": 19, "name": "Central Coast", "code": "CCo", "color": "#769289", "order": 10}, {"idx": 17, "name": "South Coast Ranges", "code": "SCoR", "color": "#9fae9a", "order": 11}, {"idx": 8, "name": "Channel Islands", "code": "ChI", "color": "#61476e", "order": 12}, {"idx": 10, "name": "South Coast", "code": "SCo", "color": "#8e75b0", "order": 13}, {"idx": 9, "name": "Transverse Ranges", "code": "TR", "color": "#c9a5c0", "order": 14}, {"idx": 11, "name": "Peninsular Ranges", "code": "PR", "color": "#b576a6", "order": 15}, {"idx": 0, "name": "Modoc Plateau", "code": "MP", "color": "#d9c3a6", "order": 16}, {"idx": 2, "name": "East of Sierra Nevada", "code": "SNE", "color": "#a69585", "order": 17}, {"idx": 4, "name": "Mojave Desert", "code": "DMoj", "color": "#c9a26d", "order": 18}, {"idx": 6, "name": "Mojave Desert Mountains", "code": "DMtns", "color": "#b86d3d", "order": 19}, {"idx": 7, "name": "Sonoran Desert", "code": "DSon", "color": "#d1a24a", "order": 20}];
const FILLS=["","","","","","","","","","","","","","","","","","","",""];
const canvas=document.getElementById('c');
const ctx=canvas.getContext('2d');
const imgBase=new Image();imgBase.src='data:image/jpeg;base64,';
const imgLines=new Image();imgLines.src='data:image/png;base64,';
const imgClick=new Image();imgClick.src='data:image/png;base64,';
const fillImgs=FILLS.map(b64=>{
  if(!b64)return null;
  const i=new Image();i.src='data:image/png;base64,'+b64;return i;
});
const hitC=document.createElement('canvas');
hitC.width=W;hitC.height=H;
const hitCtx=hitC.getContext('2d',{willReadFrequently:true});
let clickData=null,loaded=0;
const activeSet=new Set();
function onLoad(){
  if(++loaded<3)return;
  hitCtx.drawImage(imgClick,0,0,W,H);
  const raw=hitCtx.getImageData(0,0,W,H).data;
  clickData=new Uint8Array(W*H);
  for(let i=0;i<W*H;i++)clickData[i]=raw[i*4];
  redraw();
}
imgBase.onload=onLoad;imgLines.onload=onLoad;imgClick.onload=onLoad;
if(imgBase.complete)onLoad();if(imgLines.complete)onLoad();if(imgClick.complete)onLoad();
function redraw(){
  ctx.drawImage(imgBase,0,0,W,H);
  activeSet.forEach(idx=>{
    const fi=fillImgs[idx];
    if(fi&&fi.complete)ctx.drawImage(fi,0,0,W,H);
    else if(fi)fi.onload=()=>redraw();
  });
  ctx.drawImage(imgLines,0,0,W,H);
}
function getAt(ex,ey){
  if(!clickData)return null;
  const r=canvas.getBoundingClientRect();
  const ix=Math.floor((ex-r.left)*W/r.width);
  const iy=Math.floor((ey-r.top)*H/r.height);
  if(ix<0||ix>=W||iy<0||iy>=H)return null;
  const v=clickData[iy*W+ix];return v===255?null:v;
}
function toggleRegion(idx){
  if(activeSet.has(idx))activeSet.delete(idx);else activeSet.add(idx);
  redraw();
}

canvas.addEventListener('click',e=>{
  const idx=getAt(e.clientX,e.clientY);
  if(idx!==null)toggleRegion(idx);
});
